// app/riverside-sample.js — the repo's declared sample Riverside-style
// episode link: a maintainer-provided local fixture, not a real Riverside
// URL. It is a self-contained "data:application/json;base64,..." manifest
// (see app/riverside.js) whose host/guest1/guest2 fields are themselves
// small "data:video/webm;base64,..." clips generated once and committed
// here — three solid-color speaker tracks (red/green/blue, ~3.2s, 160x90,
// each with a distinct audio tone), enough to exercise the real import ->
// preview -> preset -> export workflow (including the audio every speaker
// must carry for export to succeed) without any network access or
// file-system permissions. The "Use sample link" button in the setup UI
// fills the import field with exactly this string; a creator (or the
// review harness) can just as well paste it directly. Classic script —
// exposed on window.PDC.riversideSample.
(function () {
  const PDC = (window.PDC = window.PDC || {});
  PDC.riversideSample = {
    LINK: "data:application/json;base64,",
  };
})();
